document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll(".highlight").forEach(e=>{if(e.querySelector(".copy-button"))return;const n=document.createElement("button");n.className="copy-button absolute top-3 right-3 text-slate-500 hover:text-slate-300 transition-colors p-1.5 rounded-md hover:bg-slate-800/50 focus:outline-none flex items-center justify-center",n.setAttribute("aria-label","Copy code to clipboard"),n.title="Copy code";const t=document.createElement("span");t.className="material-symbols-outlined text-lg pointer-events-none",t.textContent="content_copy",n.appendChild(t),e.appendChild(n),n.addEventListener("click",async()=>{const n=e.querySelector("code");if(!n)return;const s=n.innerText||n.textContent;try{await navigator.clipboard.writeText(s),t.textContent="check",t.classList.remove("text-slate-500"),t.classList.add("text-green-500"),setTimeout(()=>{t.textContent="content_copy",t.classList.add("text-slate-500"),t.classList.remove("text-green-500")},2e3)}catch(e){console.error("Failed to copy text: ",e),t.textContent="error",t.classList.add("text-red-500")}})})})